func solve(n int64, edges [][]int64, k int64) int64 {
    var maxTime int64 = 0
    for _, e := range edges {
        if e[2] > maxTime {
            maxTime = e[2]
        }
    }
    low, high := int64(0), maxTime + 1
    ans := high

    for low <= high {
        mid := (low + high) / 2
        parent := make([]int64, n)
        rank := make([]int64, n)
        var i int64
        for i = 0; i < n; i++ {
            parent[i] = i
            rank[i] = 0
        }

        comp := n
        for _, e := range edges {
            u, v, time := e[0], e[1], e[2]
            if time > mid {
                ru := u
                for parent[ru] != ru {
                    ru = parent[ru]
                }
                temp := u
                for parent[temp] != ru {
                    next := parent[temp]
                    parent[temp] = ru
                    temp = next
                }

                rv := v
                for parent[rv] != rv {
                    rv = parent[rv]
                }
                temp = v
                for parent[temp] != rv {
                    next := parent[temp]
                    parent[temp] = rv
                    temp = next
                }

                if ru != rv {
                    if rank[ru] < rank[rv] {
                        parent[ru] = rv
                    } else if rank[ru] > rank[rv] {
                        parent[rv] = ru
                    } else {
                        parent[rv] = ru
                        rank[ru]++
                    }
                    comp--
                }
            }
        }

        if comp >= k {
            ans = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    return ans
}
```

