type dsu struct {
    parent []int
    rank   []int
    comps  int
}

func newDSU(n int) *dsu {
    parent := make([]int, n)
    rank := make([]int, n)
    for i := 0; i < n; i++ {
        parent[i] = i
        rank[i] = 0
    }
    return &dsu{parent, rank, n}
}

func (d *dsu) find(x int) int {
    if d.parent[x] != x {
        d.parent[x] = d.find(d.parent[x])
    }
    return d.parent[x]
}

func (d *dsu) union(x, y int) bool {
    rx := d.find(x)
    ry := d.find(y)
    if rx == ry {
        return false
    }
    if d.rank[rx] < d.rank[ry] {
        d.parent[rx] = ry
    } else if d.rank[rx] > d.rank[ry] {
        d.parent[ry] = rx
    } else {
        d.parent[rx] = ry
        d.rank[ry]++
    }
    d.comps--
    return true
}

func comp(n int, edges [][]int64, t int64) int {
    d := newDSU(n)
    for _, e := range edges {
        if e[2] > t {
            u := int(e[0])
            v := int(e[1])
            d.union(u, v)
        }
    }
    return d.comps
}

func solve(n int64, edges [][]int64, k int64) int64 {
