            max_time = e[2]
        }
    }
    high := max_time + 1
    low := int64(0)

    for low < high {
        mid := (low + high) / 2
        comps := comp(int(n), edges, mid)
        if comps >= int(k) {
            high = mid
        } else {
            low = mid + 1
        }
    }

    return low
}
```

